import type { ClassValue } from '@soybeanjs/headless/types';
import type { WatermarkCompactProps, WatermarkUi } from '@soybeanjs/headless/watermark';

/**
 * Properties for the SWatermark component.
 */
export interface WatermarkProps extends WatermarkCompactProps {
  /**
   * The class attribute for the root element.
   */
  class?: ClassValue;
  /**
   * UI class overrides for each slot.
   */
  ui?: Partial<WatermarkUi>;
  /**
   * When true, the watermark overlay is fixed to the viewport instead of the parent container.
   *
   * @defaultValue false
   */
  fullscreen?: boolean;
}

export { default as SWatermark } from './watermark.vue';

export type * from '@soybeanjs/headless/watermark';
export type { WatermarkProps } from './types';

// @unocss-include
import { scv } from '@soybeanjs/cva';

export const watermarkVariants = scv({
  slots: {
    root: 'relative',
    overlay: 'absolute inset-0 pointer-events-none bg-repeat'
  },
  variants: {
    fullscreen: {
      true: {
        root: 'static',
        overlay: 'fixed inset-0 z-9999 pointer-events-none bg-repeat'
      }
    }
  }
});
